mapper.select:
SELECT categoryno, name, cnt, seqno, visible, rdate
FROM category
WHERE categoryno = #{categoryno}

mapper.update:
UPDATE category
SET name = #{name}, cnt = #{cnt}, seqno = #{seqno}, visible = #{visible}, rdate=sysdate
WHERE categoryno = #{categoryno}

mapper.select:
SELECT categoryno, name, cnt, seqno, visible, rdate
FROM (
SELECT categoryno, name, cnt, seqno, visible, rdate, ROWNUM as r
FROM (
SELECT categoryno, name, cnt, seqno, visible, rdate
FROM category

  WHERE UPPER(name) LIKE '%' || UPPER(#{word}) || '%'

ORDER BY seqno ASC
)
WHERE ROWNUM <= #{end_num}
)
WHERE r >= #{start_num}
